-- 1) Edge idempotency: one row per logical event, ever.
CREATE TABLE settlement.processed_event (
  event_type   text   NOT NULL,
  external_id  text   NOT NULL,
  processed_at timestamptz NOT NULL DEFAULT now(),
  PRIMARY KEY (event_type, external_id)
);

-- 2) Ledger guard: a given group can be credited for a given type exactly once.
ALTER TABLE settlement.ledger_entry
  ADD CONSTRAINT uq_ledger_group_type
  UNIQUE (fulfillment_group_id, entry_type);

-- Settlement worker, all in one transaction:
BEGIN;

INSERT INTO settlement.processed_event (event_type, external_id)
VALUES ('ShipmentDelivered', $1)
ON CONFLICT (event_type, external_id) DO NOTHING;
-- 0 rows inserted => duplicate delivery => COMMIT and ACK without side effects.

-- Only reached on first delivery of this event:
INSERT INTO settlement.ledger_entry
  (fulfillment_group_id, entry_type, amount_krw, direction)
VALUES ($2, 'SUPPLIER_PAYOUT', $3, 'CREDIT');
-- uq_ledger_group_type is the last line of defense against a double posting.

COMMIT;

// Search-projection worker: only newer versions win.
async function projectSku(evt: SkuUpdatedEvent): Promise<void> {
  await openSearch.update({
    index: 'sku',
    id: evt.skuId,
    body: {
      // Conditional script: ignore anything not strictly newer.
      script: {
        source:
          'if (ctx._source.version == null || params.v > ctx._source.version) ' +
          '{ ctx._source = params.doc } else { ctx.op = "none"; }',
        params: { v: evt.version, doc: evt.doc },
      },
      upsert: { ...evt.doc, version: evt.version },
    },
  });
}

// Checkout: search is never authoritative for money. Re-price from Postgres.
async function priceCartItem(item: CartItem, buyerOrgId: string) {
  const price = await pricing.resolvePrice({
    skuId: item.skuId,
    buyerOrgId,            // ContractPrice first, then PriceList fallback
    asOf: new Date(),
  });
  // Snapshotted onto OrderLine at placement — immutable thereafter.
  return { skuId: item.skuId, unitPriceKrw: price.unitPriceKrw };
}

// 1) Always acquire locks in the SAME global order: sorted by sku_id.
async function confirmReservations(tx: Tx, lines: OrderLine[]) {
  const ordered = [...lines].sort((a, b) => (a.skuId < b.skuId ? -1 : 1));
  for (const line of ordered) {
    await tx.query(
      `SELECT available FROM inventory.inventory_item
        WHERE sku_id = $1 AND location_id = $2 FOR UPDATE`,
      [line.skuId, line.locationId],
    );
    await decrementAndConfirm(tx, line);
  }
}

// 2) Bounded retry on deadlock (40P01) and serialization failures (40001).
async function withDeadlockRetry<T>(fn: () => Promise<T>, max = 4): Promise<T> {
  for (let attempt = 1; ; attempt++) {
    try {
      return await fn();
    } catch (e: any) {
      if ((e.code === '40P01' || e.code === '40001') && attempt < max) {
        await sleep(20 * attempt + Math.random() * 20); // jittered backoff
        continue;
      }
      throw e;
    }
  }
}

// Handler is idempotent: record the dedup id before the side effect.
async function handleMessage(msg: SqsMessage): Promise<void> {
  const dedupId = msg.attributes.MessageDeduplicationId ?? msg.messageId;

  const firstTime = await db.tx(async (tx) => {
    const res = await tx.query(
      `INSERT INTO notifications.processed_message (dedup_id)
         VALUES ($1) ON CONFLICT (dedup_id) DO NOTHING
       RETURNING dedup_id`,
      [dedupId],
    );
    return res.rowCount === 1; // false => already handled => skip side effect
  });

  if (!firstTime) return;       // safe no-op on redelivery
  await sendNotification(msg.body);
}

